<template><div class="page"><header class="page-head"><div><h1>Journaux</h1><p>Diagnostic applicatif, planificateur et actions administratives.</p></div><button class="icon-button" :disabled="loading" title="Actualiser" @click="load"><RefreshCw :class="{spin:loading}"/></button></header>
<div class="segmented page-tabs"><button v-for="item in tabs" :key="item.id" :class="{active:tab===item.id}" @click="tab=item.id;load()">{{ item.label }}</button></div><div class="toolbar wrap"><input v-model="search" class="search" type="search" placeholder="Filtrer les journaux"><select v-if="tab==='app'" v-model="level"><option value="">Tous les niveaux</option><option>INFO</option><option>WARNING</option><option>ERROR</option><option>CRITICAL</option></select><select v-if="tab==='polls'" v-model="job" @change="load"><option value="">Toutes les taches</option><option v-for="name in jobs" :key="name">{{ name }}</option></select><button v-if="tab==='pending'&&rows.length" class="secondary danger" @click="purge"><Trash2/>Purger la file</button></div><p v-if="error" class="notice error-text">{{ error }}</p>
<section class="panel table-wrap"><table><thead><tr><th>Date</th><th>Type</th><th>Description</th><th v-if="tab!=='app'">Resultat</th></tr></thead><tbody><tr v-for="row in filtered" :key="keyOf(row)"><td>{{ dateOf(row) }}</td><td><span class="badge" :class="badgeOf(row)">{{ typeOf(row) }}</span></td><td><strong>{{ titleOf(row) }}</strong><small class="table-detail">{{ detailOf(row) }}</small></td><td v-if="tab!=='app'">{{ resultOf(row) }}</td></tr></tbody></table><p v-if="!loading&&!filtered.length" class="empty">Aucune entree pour ce filtre.</p></section></div></template>
<script setup>import { computed,onMounted,ref } from 'vue';import { RefreshCw,Trash2 } from '@lucide/vue';import { api } from '@/api';
const tab=ref('app'),rows=ref([]),loading=ref(false),error=ref(''),search=ref(''),level=ref(''),job=ref('');const tabs=[{id:'app',label:'Application'},{id:'polls',label:'Taches planifiees'},{id:'audit',label:'Audit admin'},{id:'pending',label:'File notifications'}];const jobs=computed(()=>[...new Set(rows.value.map(x=>x.job).filter(Boolean))]);const filtered=computed(()=>rows.value.filter(row=>(!level.value||row.level===level.value)&&(!search.value||JSON.stringify(row).toLowerCase().includes(search.value.toLowerCase()))));
function endpoint(){if(tab.value==='polls')return `/api/poll-history?limit=200${job.value?`&job=${encodeURIComponent(job.value)}`:''}`;if(tab.value==='audit')return '/api/admin-action-logs?limit=200';if(tab.value==='pending')return '/api/notifications/pending';return '/api/logs'}async function load(){loading.value=true;error.value='';try{const data=await api(endpoint());rows.value=Array.isArray(data)?data:(data.items||[])}catch(e){error.value=e.message}finally{loading.value=false}}async function purge(){if(!confirm('Purger toutes les notifications en attente ?'))return;await api('/api/notifications/pending/purge',{method:'POST',body:JSON.stringify({ids:[],mark_handled:false})});await load()}
function keyOf(r){return `${tab.value}-${r.id||r.time||r.started_at}-${r.message||r.action||r.job}`}function dateOf(r){const v=r.time||r.started_at||r.created_at;return v?new Intl.DateTimeFormat('fr-FR',{dateStyle:'short',timeStyle:'medium'}).format(new Date(v.replace?.(' ','T')||v)):'-'}function typeOf(r){return r.level||r.job||r.action||r.event_label||r.event||'-'}function titleOf(r){return r.message||r.summary||r.media_title||`Demande #${r.req_id||'-'}`}function detailOf(r){if(tab.value==='app')return r.logger||'';if(tab.value==='polls')return r.error_detail||`${r.items_processed||0} element(s) traites`;if(tab.value==='audit')return r.actor_name||'';return (r.recipients||[]).join(', ')}function resultOf(r){if(tab.value==='polls')return r.errors?`${r.errors} erreur(s)`:`${r.duration_ms||0} ms`;if(tab.value==='audit')return `${r.target_count||0} cible(s)`;return r.valid?'Valide':'Invalide'}function badgeOf(r){if(r.level==='ERROR'||r.level==='CRITICAL'||r.errors||r.valid===false)return 'failed';if(r.level==='WARNING')return 'pending';return 'available'}onMounted(load);</script>
